//! M2 parity gate — the amortized-read K-quant matvec matches solo (per lane).
//!
//! `decode_step_batch`'s residency win (WarpBatchAmortization: one weight read
//! serves the wave) is realized by `mat_vec_q{4,6}k_batch` — they dequantize
//! each weight row ONCE and dot it against every lane's activation. q3
//! (qwen2.5-3b) is a Q6_K/Q4_K knot, so the batched path that actually serves
//! it must produce, per lane, logits that MATCH the solo `mat_vec_q{4,6}k` a
//! single-sequence `forward_one` uses — within the codebase's parity standard
//! (`decode_step_batch_parity`: argmax-stable, maxdiff bounded). The batch
//! kernel reduces the shared-read dot in a different SIMD grouping than solo,
//! so logits agree to ~1e-6 (accumulation order), not bit-for-bit — which is
//! why token identity is what matters, and it holds. The existing
//! `decode_step_batch_parity` exercises only the F32 path (a different kernel);
//! this gate certifies the K-quant kernels q3 runs on.
//!
//! Grounds: `gnosis-math/Gnosis/WarpBatchAmortization.lean` (sharedCost = w +
//! lanes·a — one read, N dots) and `VGpuWarp.lean :batch_isolation` (per-lane
//! result equals the solo result — batching changes throughput, not tokens).
//!
//! Validity, not "correctness of quantization", is what the test needs: batch
//! lane k and solo(xs[k]) dequantize the SAME bytes `w`, so they must agree
//! (to accumulation-order tolerance) for ANY dequant-to-finite quant bytes.
//! We build deterministic valid blocks. TOL matches the raw-matvec scale
//! (observed ~2e-6; the full-pipeline gate asserts argmax exact).

use distributed_inference::math::{
    mat_vec_q4k, mat_vec_q4k_batch, mat_vec_q6k, mat_vec_q6k_batch,
};

const ROWS: usize = 12; // output rows (e.g. a small projection)
const COLS: usize = 256; // one K-superblock per row
const LANES: usize = 4; // the decode wave
/// Accumulation-order tolerance for the shared-read dot (batch SIMD grouping
/// differs from solo). Raw-matvec scale; the pipeline gate asserts argmax exact.
const TOL: f32 = 1e-3;

fn assert_lane_parity(tag: &str, k: usize, batched: &[f32], solo: &[f32]) {
    assert!(batched.iter().all(|v| v.is_finite()), "{tag} lane {k}: non-finite batched logits");
    let maxdiff = batched
        .iter()
        .zip(solo)
        .map(|(a, b)| (a - b).abs())
        .fold(0.0f32, f32::max);
    assert!(
        maxdiff < TOL,
        "{tag} lane {k}: batched vs solo maxdiff {maxdiff} >= {TOL} — amortized read diverged"
    );
}

/// f16 0.0625 (2^-4) — an exact small scale, so dequant is finite + bounded.
const F16_SCALE: [u8; 2] = [0x00, 0x2C];
/// f16 0.03125 (2^-5) for the Q4_K dmin.
const F16_DMIN: [u8; 2] = [0x00, 0x28];

/// Deterministic valid Q6_K weight bytes for ROWS×COLS (210 bytes / 256 elems).
/// Layout (per dequantize_q6k_row): ql[128] qh[64] sc[16 i8] d[2 f16].
fn build_q6k(rows: usize, cols: usize) -> Vec<u8> {
    assert_eq!(cols % 256, 0);
    let bpr = cols / 256;
    let mut w = Vec::with_capacity(rows * bpr * 210);
    let mut s: u32 = 0x1234_5678;
    let mut next = || {
        s = s.wrapping_mul(1_664_525).wrapping_add(1_013_904_223);
        (s >> 24) as u8
    };
    for _ in 0..rows * bpr {
        for _ in 0..128 {
            w.push(next());
        } // ql
        for _ in 0..64 {
            w.push(next());
        } // qh
        for _ in 0..16 {
            w.push((next() % 9) as i8 as u8);
        } // sc (small i8, keep magnitude sane)
        w.extend_from_slice(&F16_SCALE); // d
    }
    w
}

/// Deterministic valid Q4_K weight bytes (144 bytes / 256 elems).
/// Layout (per dequantize_q4k_row): d[2] dmin[2] scales[12] qs[128].
fn build_q4k(rows: usize, cols: usize) -> Vec<u8> {
    assert_eq!(cols % 256, 0);
    let bpr = cols / 256;
    let mut w = Vec::with_capacity(rows * bpr * 144);
    let mut s: u32 = 0x9E37_79B9;
    let mut next = || {
        s = s.wrapping_mul(1_664_525).wrapping_add(1_013_904_223);
        (s >> 24) as u8
    };
    for _ in 0..rows * bpr {
        w.extend_from_slice(&F16_SCALE); // d
        w.extend_from_slice(&F16_DMIN); // dmin
        for _ in 0..12 {
            w.push(next());
        } // scales (6-bit packed; any bytes valid)
        for _ in 0..128 {
            w.push(next());
        } // qs
    }
    w
}

fn lanes(cols: usize) -> Vec<Vec<f32>> {
    (0..LANES)
        .map(|k| {
            (0..cols)
                .map(|i| ((i as f32 * 0.017 + k as f32 * 0.3).sin()) * 0.1)
                .collect()
        })
        .collect()
}

#[test]
fn q6k_batch_matches_solo_per_lane() {
    let w = build_q6k(ROWS, COLS);
    let xs = lanes(COLS);

    // Batched: one dequant per row serves all lanes.
    let mut outs: Vec<Vec<f32>> = vec![vec![0.0f32; ROWS]; LANES];
    {
        let mut slices: Vec<&mut [f32]> = outs.iter_mut().map(|v| v.as_mut_slice()).collect();
        let x_refs: Vec<&[f32]> = xs.iter().map(|v| v.as_slice()).collect();
        mat_vec_q6k_batch(&mut slices, &x_refs, &w, LANES, COLS);
    }

    // Solo reference per lane.
    for (k, x) in xs.iter().enumerate() {
        let mut solo = vec![0.0f32; ROWS];
        mat_vec_q6k(&mut solo, x, &w, ROWS, COLS);
        assert_lane_parity("Q6_K", k, &outs[k], &solo);
    }
}

#[test]
fn q4k_batch_matches_solo_per_lane() {
    let w = build_q4k(ROWS, COLS);
    let xs = lanes(COLS);

    let mut outs: Vec<Vec<f32>> = vec![vec![0.0f32; ROWS]; LANES];
    {
        let mut slices: Vec<&mut [f32]> = outs.iter_mut().map(|v| v.as_mut_slice()).collect();
        let x_refs: Vec<&[f32]> = xs.iter().map(|v| v.as_slice()).collect();
        mat_vec_q4k_batch(&mut slices, &x_refs, &w, LANES, COLS);
    }

    for (k, x) in xs.iter().enumerate() {
        let mut solo = vec![0.0f32; ROWS];
        mat_vec_q4k(&mut solo, x, &w, ROWS, COLS);
        assert_lane_parity("Q4_K", k, &outs[k], &solo);
    }
}

/// Multi-block rows (cols = 512) — exercise blocks_per_row > 1, the real q3
/// projection widths (2048, 11008) all being 256-multiples.
#[test]
fn q6k_batch_matches_solo_multiblock() {
    let cols = 512;
    let w = build_q6k(ROWS, cols);
    let xs = lanes(cols);
    let mut outs: Vec<Vec<f32>> = vec![vec![0.0f32; ROWS]; LANES];
    {
        let mut slices: Vec<&mut [f32]> = outs.iter_mut().map(|v| v.as_mut_slice()).collect();
        let x_refs: Vec<&[f32]> = xs.iter().map(|v| v.as_slice()).collect();
        mat_vec_q6k_batch(&mut slices, &x_refs, &w, LANES, cols);
    }
    for (k, x) in xs.iter().enumerate() {
        let mut solo = vec![0.0f32; ROWS];
        mat_vec_q6k(&mut solo, x, &w, ROWS, cols);
        assert_lane_parity("Q6_K multiblock", k, &outs[k], &solo);
    }
}
